/// <summary>
/// Represents the ETGSPAIN Unload Port table, which contains information about unload ports.
/// </summary>
public class ETGSPAINPurchUnloadPortTable extends common
{
}

Method.Source:
/// <summary>
/// Finds a specific record in the ETGSPAINPurchUnloadPortTable by its UnloadPortId.
/// </summary>
/// <param name="_ETGSPAINPurchUnloadPortId">The ID of the unload port.</param>
/// <param name="_forUpdate">Optional: Indicates if the record should be locked for update.</param>
/// <returns>Returns the matching ETGSPAINPurchUnloadPortTable record, or null if not found.</returns>
static ETGSPAINPurchUnloadPortTable find(ETGSPAINPurchUnloadPortId    _ETGSPAINPurchUnloadPortId,
                                        boolean             _forUpdate = false)
{
    ETGSPAINPurchUnloadPortTable unloadPortTable;

    if (_ETGSPAINPurchUnloadPortId)
    {
        if (_forUpdate)
        {
            unloadPortTable.selectForUpdate(_forUpdate);
        }

        select firstonly unloadPortTable
            where unloadPortTable.UnloadPortId == _ETGSPAINPurchUnloadPortId;
    }

    return unloadPortTable;
}

/// <summary>
/// Checks whether a specific unload port exists in the ETGSPAINPurchUnloadPortTable.
/// </summary>
/// <param name="_ETGSPAINPurchUnloadPortId">The ID of the unload port.</param>
/// <returns>Returns true if the unload port exists, otherwise false.</returns>
static boolean exist(ETGSPAINPurchUnloadPortId    _ETGSPAINPurchUnloadPortId)
{
    return _ETGSPAINPurchUnloadPortId && (select firstonly RecId from ETGSPAINPurchUnloadPortTable
                                            index hint UnloadPortIdx
                                            where ETGSPAINPurchUnloadPortTable.UnloadPortId == _ETGSPAINPurchUnloadPortId).RecId != 0;
}

/// <summary>
/// Lookup function to display cities associated with the unload ports.
/// </summary>
/// <param name="_ETGSPAINPurchUnloadPortTable">The ETGSPAINPurchUnloadPortTable record to perform the lookup on.</param>
/// <param name="_formControl">The form control used for the lookup.</param>
public static void addressCityLookUp(ETGSPAINPurchUnloadPortTable _ETGSPAINPurchUnloadPortTable, FormControl _formControl)
{
    SysTableLookup          sysTableLookup              = SysTableLookup::newParameters(tableNum(LogisticsAddressCity), _formControl);

    Query                   query                       = new Query();
    QueryBuildDataSource    qbdsLogisticsAddressCity    = SysQuery::findOrCreateDataSource(query, tableNum(LogisticsAddressCity));;
    QueryBuildRange         qbrCountryRegionId          = SysQuery::findOrCreateRange(qbdsLogisticsAddressCity, fieldNum(LogisticsAddressCity, CountryRegionId));
    QueryBuildRange         qbrName                     = SysQuery::findOrCreateRange(qbdsLogisticsAddressCity, fieldNum(LogisticsAddressCity, Name));

    if (_ETGSPAINPurchUnloadPortTable.CountryRegionId)
    {
        qbrCountryRegionId.value(_ETGSPAINPurchUnloadPortTable.CountryRegionId);
    }

    if (_ETGSPAINPurchUnloadPortTable.AdressCity)
    {
        qbrName.value(queryValue(_ETGSPAINPurchUnloadPortTable.AdressCity));
    }

    sysTableLookup.addLookupfield(fieldNum(LogisticsAddressCity, Name));
    sysTableLookup.addLookupfield(fieldNum(LogisticsAddressCity, Description));
    sysTableLookup.addLookupfield(fieldNum(LogisticsAddressCity, StateId));
    sysTableLookup.addLookupfield(fieldNum(LogisticsAddressCity, CountyId));

    sysTableLookup.parmQuery(query);

    sysTableLookup.performFormLookup();
}
